import{_ as e,o as r,c as t,ae as i}from"./chunks/framework.CFyvOAXl.js";const p=JSON.parse('{"title":"23种设计模式（updating）","description":"","frontmatter":{},"headers":[],"relativePath":"program/cpp/designPattern.md","filePath":"program/cpp/designPattern.md","lastUpdated":1666363606000}'),h={name:"program/cpp/designPattern.md"};function o(l,a,n,d,s,_){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="_23种设计模式-updating" tabindex="-1">23种设计模式（updating） <a class="header-anchor" href="#_23种设计模式-updating" aria-label="Permalink to &quot;23种设计模式（updating）&quot;">​</a></h1><h2 id="_1-前言" tabindex="-1">1 前言 <a class="header-anchor" href="#_1-前言" aria-label="Permalink to &quot;1 前言&quot;">​</a></h2><p>设计模式是软件开发人员在软件开发过程中面临的一般问题的解决方案。这些解决方案是众多软件开发人员经过相当长的一段时间的试验和错误总结出来的。</p><h2 id="_2-uml和时序图" tabindex="-1">2 UML和时序图 <a class="header-anchor" href="#_2-uml和时序图" aria-label="Permalink to &quot;2 UML和时序图&quot;">​</a></h2><h3 id="_2-1-类之间的关系" tabindex="-1">2.1 类之间的关系 <a class="header-anchor" href="#_2-1-类之间的关系" aria-label="Permalink to &quot;2.1 类之间的关系&quot;">​</a></h3><ul><li><p>泛化关系 generalization</p><p>继承关系为 is - a，UML图中泛化关系用带空心箭头的直线表示</p></li><li><p>实现关系 realize</p><p>UML图中实现关系用一条带空心箭头的虚线表示</p></li><li><p>聚合关系 aggregation</p><p>UML图中组合关系用一条带空心菱形直线表示</p></li><li><p>组合关系 composition</p><p>UML图中组合关系用一条带实心菱形直线表示</p></li><li><p>关联关系 association</p><p>UML图中关联关系用一条直线表示</p></li><li><p>依赖关系 dependency</p><p>UML图中依赖关系用带箭头的虚线表示</p></li></ul><h3 id="_2-2-时序图" tabindex="-1">2.2 时序图 <a class="header-anchor" href="#_2-2-时序图" aria-label="Permalink to &quot;2.2 时序图&quot;">​</a></h3><p>时序图是显示对象之间交互的图，按照时间顺序排列。</p><p>元素：对象、生命线、控制焦点、消息。</p><h2 id="_3-设计模式" tabindex="-1">3 设计模式 <a class="header-anchor" href="#_3-设计模式" aria-label="Permalink to &quot;3 设计模式&quot;">​</a></h2><p>根据模式是用来完成什么工作来划分，这种方式可分为5个创建型模式、7个结构型模式和11个行为型模式 3 种。</p><h3 id="_3-1-创建型模式" tabindex="-1">3.1 创建型模式 <a class="header-anchor" href="#_3-1-创建型模式" aria-label="Permalink to &quot;3.1 创建型模式&quot;">​</a></h3><h4 id="_3-1-1-简单工厂模式" tabindex="-1">3.1.1 简单工厂模式 <a class="header-anchor" href="#_3-1-1-简单工厂模式" aria-label="Permalink to &quot;3.1.1 简单工厂模式&quot;">​</a></h4><p>简单工厂模式最大的问题在于工厂类的职责相对过重，增加新的产品需要修改工厂类的判断逻辑，这一点与开闭原则是相违背的。</p><h4 id="_3-1-2-工厂方法模式" tabindex="-1">3.1.2 工厂方法模式 <a class="header-anchor" href="#_3-1-2-工厂方法模式" aria-label="Permalink to &quot;3.1.2 工厂方法模式&quot;">​</a></h4><p>在工厂方法模式中，核心的工厂类不再负责所有产品的创建，而是将具体创建工作交给子类去做。</p><h4 id="_3-1-3-抽象工厂模式" tabindex="-1">3.1.3 抽象工厂模式 <a class="header-anchor" href="#_3-1-3-抽象工厂模式" aria-label="Permalink to &quot;3.1.3 抽象工厂模式&quot;">​</a></h4><p>有时候我们需要一个工厂可以提供多个产品对象，而不是单一的产品对象。</p><p>当系统所提供的工厂所需生产的具体产品并不是一个简单的对象，而是多个位于不同产品等级结构中属于不同类型的具体产品时需要使用抽象工厂模式。</p><h4 id="_3-1-4-建造者模式" tabindex="-1">3.1.4 建造者模式 <a class="header-anchor" href="#_3-1-4-建造者模式" aria-label="Permalink to &quot;3.1.4 建造者模式&quot;">​</a></h4><p>建造者模式可以将部件和其组装过程分开，一步一步创建一个复杂的对象。用户只需要指定复杂对象的类型就可以得到该对象，而无须知道其内部的具体构造细节。</p><h4 id="_3-1-5-单例模式" tabindex="-1">3.1.5 单例模式 <a class="header-anchor" href="#_3-1-5-单例模式" aria-label="Permalink to &quot;3.1.5 单例模式&quot;">​</a></h4><p>让类自身负责保存它的唯一实例。这个类可以保证没有其他实例被创建，并且它可以提供一个访问该实例的方法</p><h3 id="_3-2-结构型模式" tabindex="-1">3.2 结构型模式 <a class="header-anchor" href="#_3-2-结构型模式" aria-label="Permalink to &quot;3.2 结构型模式&quot;">​</a></h3><h4 id="_3-2-1-适配器模式" tabindex="-1">3.2.1 适配器模式 <a class="header-anchor" href="#_3-2-1-适配器模式" aria-label="Permalink to &quot;3.2.1 适配器模式&quot;">​</a></h4><h4 id="_3-2-2-桥接模式" tabindex="-1">3.2.2 桥接模式 <a class="header-anchor" href="#_3-2-2-桥接模式" aria-label="Permalink to &quot;3.2.2 桥接模式&quot;">​</a></h4><h4 id="_3-2-3-装饰模式" tabindex="-1">3.2.3 装饰模式 <a class="header-anchor" href="#_3-2-3-装饰模式" aria-label="Permalink to &quot;3.2.3 装饰模式&quot;">​</a></h4><h4 id="_3-2-4-外观模式" tabindex="-1">3.2.4 外观模式 <a class="header-anchor" href="#_3-2-4-外观模式" aria-label="Permalink to &quot;3.2.4 外观模式&quot;">​</a></h4><h4 id="_3-2-5-享元模式" tabindex="-1">3.2.5 享元模式 <a class="header-anchor" href="#_3-2-5-享元模式" aria-label="Permalink to &quot;3.2.5 享元模式&quot;">​</a></h4><h4 id="_3-2-6-代理模式" tabindex="-1">3.2.6 代理模式 <a class="header-anchor" href="#_3-2-6-代理模式" aria-label="Permalink to &quot;3.2.6 代理模式&quot;">​</a></h4><h4 id="_3-2-7-组合模式" tabindex="-1">3.2.7 组合模式 <a class="header-anchor" href="#_3-2-7-组合模式" aria-label="Permalink to &quot;3.2.7 组合模式&quot;">​</a></h4><h3 id="_3-3-行为型模式" tabindex="-1">3.3 行为型模式 <a class="header-anchor" href="#_3-3-行为型模式" aria-label="Permalink to &quot;3.3 行为型模式&quot;">​</a></h3><h4 id="_3-3-1-命令模式" tabindex="-1">3.3.1 命令模式 <a class="header-anchor" href="#_3-3-1-命令模式" aria-label="Permalink to &quot;3.3.1 命令模式&quot;">​</a></h4><h4 id="_3-3-2-中介者模式" tabindex="-1">3.3.2 中介者模式 <a class="header-anchor" href="#_3-3-2-中介者模式" aria-label="Permalink to &quot;3.3.2 中介者模式&quot;">​</a></h4><h4 id="_3-3-3-观察者模式" tabindex="-1">3.3.3 观察者模式 <a class="header-anchor" href="#_3-3-3-观察者模式" aria-label="Permalink to &quot;3.3.3 观察者模式&quot;">​</a></h4><h4 id="_3-3-4-状态模式" tabindex="-1">3.3.4 状态模式 <a class="header-anchor" href="#_3-3-4-状态模式" aria-label="Permalink to &quot;3.3.4 状态模式&quot;">​</a></h4><h4 id="_3-3-5-策略模式" tabindex="-1">3.3.5 策略模式 <a class="header-anchor" href="#_3-3-5-策略模式" aria-label="Permalink to &quot;3.3.5 策略模式&quot;">​</a></h4><h4 id="_3-3-6-访问者模式" tabindex="-1">3.3.6 访问者模式 <a class="header-anchor" href="#_3-3-6-访问者模式" aria-label="Permalink to &quot;3.3.6 访问者模式&quot;">​</a></h4><h4 id="_3-3-7-模板模式" tabindex="-1">3.3.7 模板模式 <a class="header-anchor" href="#_3-3-7-模板模式" aria-label="Permalink to &quot;3.3.7 模板模式&quot;">​</a></h4><h4 id="_3-3-8-备忘录模式" tabindex="-1">3.3.8 备忘录模式 <a class="header-anchor" href="#_3-3-8-备忘录模式" aria-label="Permalink to &quot;3.3.8 备忘录模式&quot;">​</a></h4><h4 id="_3-3-9-迭代器模式" tabindex="-1">3.3.9 迭代器模式 <a class="header-anchor" href="#_3-3-9-迭代器模式" aria-label="Permalink to &quot;3.3.9 迭代器模式&quot;">​</a></h4><h4 id="_3-3-10-解释器模式" tabindex="-1">3.3.10 解释器模式 <a class="header-anchor" href="#_3-3-10-解释器模式" aria-label="Permalink to &quot;3.3.10 解释器模式&quot;">​</a></h4><h4 id="_3-3-11-责任者模式" tabindex="-1">3.3.11 责任者模式 <a class="header-anchor" href="#_3-3-11-责任者模式" aria-label="Permalink to &quot;3.3.11 责任者模式&quot;">​</a></h4><h2 id="_4-参考资料" tabindex="-1">4 参考资料 <a class="header-anchor" href="#_4-参考资料" aria-label="Permalink to &quot;4 参考资料&quot;">​</a></h2><p>[1] 图说设计模式</p><p><a href="https://design-patterns.readthedocs.io/zh_CN/latest/" target="_blank" rel="noreferrer">https://design-patterns.readthedocs.io/zh_CN/latest/</a></p>',46)])])}const u=e(h,[["render",o]]);export{p as __pageData,u as default};
